mapper.select:
select notice_topic.id topicId, notice_topic.name topicName, notice_topic.code topicCode, GROUP_CONCAT(notice_tmpl.id) templateIds, GROUP_CONCAT(notice_topic_range.id) rangeIds from notice_topic left join notice_topic_tmpl_rel on notice_topic_tmpl_rel.notice_topic_id = notice_topic.id left join notice_tmpl on notice_topic_tmpl_rel.notice_tmpl_id = notice_tmpl.id left join notice_protocol on notice_protocol.id = notice_tmpl.notice_protocol_id left join notice_topic_range on notice_topic_range.notice_topic_id = notice_topic.id
notice_topic.name like concat('%',#{name},'%')
notice_topic.code like concat('%',#{code},'%')
notice_tmpl.name like concat('%',#{templateName},'%')
and notice_topic.notice_topic_type_id = #{topicTree}
notice_protocol.id = #{protocolId}
group by notice_topic.id, notice_topic.name, notice_topic.code order by notice_topic.create_time desc limit #{start}, #{end}

SELECT topic.*,tmpl.name as template_name FROM notice_topic topic 
left join notice_topic_tmpl_rel rel on topic.id=rel.notice_topic_id 
left join notice_tmpl tmpl on tmpl.id =rel.notice_tmpl_id ${ew.customSqlSegment}
